// nodes.go
package runai

import (
	"context"
	"encoding/json"
	"fmt"
	"maps"
	"net/http"
	"time"

	"github.com/samber/lo"
)

type Node struct {
	ID   string `json:"id"`
	Name string `json:"name"`
}

type ListNodesResponse struct {
	Nodes []Node `json:"nodes"`
	Next  int    `json:"next"`
}

// ListNodes lists nodes (single page, max 500).
func (s *Service) ListNodes(ctx context.Context, params ListWorkloadParams) (*ListNodesResponse, error) {
	if params.Limit > 500 {
		return nil, fmt.Errorf("limit must be less than 500")
	}
	resp, err := s.client.R().
		SetContext(ctx).
		SetHeader("Accept", "application/json").
		SetQueryParams(map[string]string{
			"limit":  fmt.Sprintf("%d", params.Limit),
			"offset": fmt.Sprintf("%d", params.Offset),
		}).
		SetResult(&ListNodesResponse{}).
		Get("/api/v1/nodes")
	if err != nil {
		return nil, err
	}
	if resp.StatusCode() != http.StatusOK {
		return nil, fmt.Errorf("failed to list nodes, status code: %d", resp.StatusCode())
	}
	return resp.Result().(*ListNodesResponse), nil
}

// ListAllNodes paginates through all nodes and records the count metric.
func (s *Service) ListAllNodes(ctx context.Context) ([]Node, error) {
	nodes := make([]Node, 0)
	for {
		resp, err := s.ListNodes(ctx, ListWorkloadParams{Limit: s.pageSize, Offset: len(nodes)})
		if err != nil {
			return nil, err
		}
		nodes = append(nodes, resp.Nodes...)
		if resp.Next == 0 {
			break
		}
	}
	s.resourceTypeMetrics.Set(int64(len(nodes)), "node")
	return nodes, nil
}

type NodeWithMetrics struct {
	Node
	Metrics Metrics `json:"metrics"`
}

var _ ResourceWithMetrics = (*NodeWithMetrics)(nil)

func (n *NodeWithMetrics) GetType() ResourceType  { return "node" }
func (n *NodeWithMetrics) GetMetrics() Metrics     { return n.Metrics }
func (n *NodeWithMetrics) MarshalJSON() ([]byte, error) {
	return json.Marshal(struct {
		ResourceType ResourceType `json:"resourceType"`
		NodeWithMetrics
	}{ResourceType: n.GetType(), NodeWithMetrics: *n})
}

// GetAllNodeWithMetrics collects metrics for all nodes, chunking at 9 metric types per request.
func (s *Service) GetAllNodeWithMetrics(ctx context.Context, params MeasurementParams) ([]NodeWithMetrics, error) {
	nodes, err := s.ListAllNodes(ctx)
	if err != nil {
		return nil, err
	}
	result := make([]NodeWithMetrics, 0, len(nodes))
	for _, node := range nodes {
		metrics := Metrics{Timestamp: params.EndTime.UTC(), Values: make(map[MetricType]float64)}
		for _, metricTypes := range lo.Chunk(params.MetricType, 9) {
			m, err := s.GetNodeMetrics(ctx, node.ID, MeasurementParams{
				MetricType: metricTypes,
				StartTime:  params.StartTime.UTC(),
				EndTime:    params.EndTime.UTC(),
			})
			if err != nil {
				// Non-fatal: log and continue
				s.logger.With("nodeID", node.ID).Errorf("failed to get node metrics: %w", err)
				continue
			}
			maps.Copy(metrics.Values, m.Values)
		}
		if len(metrics.Values) > 0 {
			result = append(result, NodeWithMetrics{Node: node, Metrics: metrics})
		}
	}
	return result, nil
}
